import { MessageEntity, PopulatedMessageEntity } from '@/entity/message.entity';
import { IConversation } from '@/models/conversation.model';
import { IMessage } from '@/models/message.model';

export interface IChatRepository {
    createConversation(
        participants: { _id: string; onModel: string }[]
    ): Promise<IConversation>;
    findConversationByParticipants(
        participants: { _id: string; onModel: string }[]
    ): Promise<IConversation | null>;
    getUserConversations(userId: string): Promise<IConversation[]>;
    getConversationById(id: string): Promise<IConversation | null>;

    createMessage(
        data: Partial<MessageEntity>
    ): Promise<PopulatedMessageEntity>;
    getMessages(
        conversationId: string,
        limit: number,
        skip: number
    ): Promise<IMessage[]>;
    markMessagesAsRead(conversationId: string, userId: string): Promise<void>;
    updateLastMessage(conversationId: string, messageId: string): Promise<void>;
    deleteMessage(messageId: string): Promise<IMessage | null>;
    getMessageById(messageId: string): Promise<IMessage | null>;
}
